"use client";
import { useEffect, useState, useCallback } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { Loader2, Monitor, Smartphone, ShieldCheck, RefreshCw, ArrowLeft } from 'lucide-react';
import DeviceModal from '@/components/DeviceModal';

export default function ScanDetailPage() {
    const { id } = useParams();
    const router = useRouter();
    const [scan, setScan] = useState<any>(null);
    const [devices, setDevices] = useState([]);
    const [selectedDevice, setSelectedDevice] = useState<any>(null);
    const [devicePorts, setDevicePorts] = useState([]);
    const [isRefreshing, setIsRefreshing] = useState(false);

    const fetchData = useCallback(async () => {
        setIsRefreshing(true);
        try {
            const resScan = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/scans/${id}`);
            if (!resScan.ok) throw new Error("Scan not found");
            const dataScan = await resScan.json();
            setScan(dataScan);

            const resDevs = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/devices/?scan_id=${id}`);
            const dataDevs = await resDevs.json();
            setDevices(dataDevs);
        } catch (err) {
            console.error("API Error:", err);
        } finally {
            setIsRefreshing(false);
        }
    }, [id]);

    useEffect(() => {
        fetchData();
        const timer = setInterval(fetchData, 5000); // Poll every 5 seconds
        return () => clearInterval(timer);
    }, [fetchData]);

    const openDevice = async (device: any) => {
        try {
            const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/devices/${device.id}/ports`);
            const ports = await res.json();
            setDevicePorts(ports);
            setSelectedDevice(device);
        } catch (err) {
            console.error("Could not fetch ports", err);
        }
    };

    if (!scan) return (
        <div className="flex flex-col items-center justify-center min-h-screen bg-slate-50">
            <Loader2 className="animate-spin text-blue-600 w-10 h-10 mb-4" />
            <p className="text-slate-500 font-medium">Loading scan data...</p>
        </div>
    );

    return (
        <div className="min-h-screen bg-slate-50 p-4 md:p-8">
            <div className="max-w-6xl mx-auto">
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-10">
                    <div>
                        <button
                            onClick={() => router.push('/scans')}
                            className="flex items-center text-slate-500 hover:text-blue-600 mb-2 transition-colors text-sm font-medium"
                        >
                            <ArrowLeft className="w-4 h-4 mr-1" /> Back to History
                        </button>
                        <h1 className="text-4xl font-black text-slate-900 flex items-center gap-3">
                            {scan.ssid || "Scanning Network..."}
                            {isRefreshing && <Loader2 className="w-5 h-5 text-blue-400 animate-spin" />}
                        </h1>
                        <p className="text-slate-400 font-mono text-xs mt-1 uppercase tracking-widest">ID: {id} • {new Date(scan.timestamp).toLocaleString()}</p>
                    </div>

                    <div className="flex items-center gap-4">
                        <button
                            onClick={fetchData}
                            className="p-3 bg-white border border-slate-200 rounded-xl hover:bg-slate-50 transition-all shadow-sm"
                            title="Refresh Data"
                        >
                            <RefreshCw className={`w-5 h-5 text-slate-600 ${isRefreshing ? 'animate-spin' : ''}`} />
                        </button>
                        <div className="bg-white px-6 py-3 rounded-2xl shadow-sm border border-slate-200 text-center min-w-[120px]">
                            <p className="text-[10px] font-bold text-slate-400 uppercase">Live Count</p>
                            <p className="text-2xl font-bold text-blue-600">{devices.length}</p>
                        </div>
                    </div>
                </div>

                {devices.length === 0 ? (
                    <div className="bg-white rounded-3xl p-20 text-center border-2 border-dashed border-slate-200 shadow-inner">
                        <div className="relative w-16 h-16 mx-auto mb-6">
                            <div className="absolute inset-0 bg-blue-100 rounded-full animate-ping opacity-25"></div>
                            <div className="relative bg-blue-500 rounded-full p-4">
                                <ShieldCheck className="w-8 h-8 text-white" />
                            </div>
                        </div>
                        <h2 className="text-xl font-bold text-slate-700">Initializing Scan</h2>
                        <p className="text-slate-400 max-w-sm mx-auto mt-2">The scanner is currently identifying hosts. Please wait a moment for devices to appear.</p>
                    </div>
                ) : (
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                        {devices.map((dev: any, index: number) => (
                            <div
                                // THE FIX: Using a combination of ID and Index ensures the key is ALWAYS unique
                                key={dev.id ? `dev-${dev.id}` : `idx-${index}`}
                                onClick={() => openDevice(dev)}
                                className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 hover:shadow-xl hover:border-blue-300 transition-all cursor-pointer group animate-in fade-in slide-in-from-bottom-2 duration-500"
                            >
                                <div className="flex justify-between items-start mb-4">
                                    <div className="bg-slate-50 p-3 rounded-xl group-hover:bg-blue-50 transition-colors">
                                        {dev.category === 'laptop' ? <Monitor className="text-slate-600 group-hover:text-blue-600" /> : <Smartphone className="text-slate-600 group-hover:text-blue-600" />}
                                    </div>
                                    <div className="w-2 h-2 rounded-full bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)]"></div>
                                </div>
                                <h3 className="font-bold text-slate-800 truncate">{dev.hostname || "Unknown Device"}</h3>
                                <p className="text-sm text-slate-400 font-mono mt-1">{dev.ip_address}</p>
                                <div className="mt-4 pt-4 border-t border-slate-50 flex justify-between items-center opacity-0 group-hover:opacity-100 transition-opacity">
                                    <span className="text-[10px] font-bold text-blue-600 uppercase">View Details</span>
                                    <ShieldCheck className="w-4 h-4 text-blue-500" />
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>

            <DeviceModal
                device={selectedDevice}
                ports={devicePorts}
                onClose={() => setSelectedDevice(null)}
            />
        </div>
    );
}